/**
 * DataTables initialisation and filter management for the course manager table.
 *
 * Key fix: DataTables is loaded with window.define hidden (no AMD conflict),
 * then manually initialised against Moodle's own jQuery instance by calling
 * the DataTables factory function directly with our $ reference.
 *
 * @module      report_coursemanager/coursetable
 * @copyright   2022 Olivier VALENTIN
 * @license     https://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define('report_coursemanager/coursetable', ['jquery'], function($) {

    /**
     * Load a script while hiding window.define so libraries that detect AMD
     * (like DataTables) fall back to global / jQuery-plugin mode instead of
     * trying to register an anonymous AMD module (which would crash RequireJS).
     *
     * After load, we also explicitly call the DataTables factory with Moodle's
     * jQuery so the plugin attaches to the correct $ instance.
     *
     * @param  {string}   src      URL to load.
     * @param  {Function} [after]  Optional callback executed after the script loads,
     *                             still within the define-hidden window.
     * @return {Promise}
     */
    var loadScriptNoAmd = function(src, after) {
        return new Promise(function(resolve) {
            var savedDefine   = window.define;
            window.define     = undefined;

            var s    = document.createElement('script');
            s.src    = src;
            s.onload = function() {
                if (typeof after === 'function') {
                    after();
                }
                // Restore RequireJS define.
                window.define = savedDefine;
                resolve();
            };
            s.onerror = function() {
                window.define = savedDefine;
                resolve();
            };
            document.head.appendChild(s);
        });
    };

    /**
     * Fix Moodle html_table: move all body <tr> into <tbody> before DataTables reads the DOM.
     */
    var fixTbody = function(tableEl) {
        var thead = tableEl.querySelector('thead');
        var tbody = tableEl.querySelector('tbody');

        if (!tbody) {
            tbody = document.createElement('tbody');
            tableEl.appendChild(tbody);
        }

        var theadRows = thead ? Array.prototype.slice.call(thead.querySelectorAll('tr')) : [];
        var allRows   = Array.prototype.slice.call(tableEl.querySelectorAll('tr'));

        allRows.forEach(function(row) {
            if (theadRows.indexOf(row) === -1 && row.parentNode !== tbody) {
                tbody.appendChild(row);
            }
        });
    };

    /**
     * Initialise DataTables and wire up filter buttons + text search.
     *
     * @param {string} tableId  HTML id of the table element to enhance.
     * @param {Object} lang     Localised strings passed from PHP via js_call_amd.
     */
    var initTable = function(tableId, lang) {
        var tableEl = document.getElementById(tableId);
        if (!tableEl) {
            return;
        }

        // Fix <tbody> BEFORE DataTables reads the DOM.
        fixTbody(tableEl);

        // DataTables was loaded without AMD awareness, so $.fn.dataTable may not
        // be attached to Moodle's $. Re-run the DataTables factory explicitly
        // with our $ so the plugin registers on the correct jQuery instance.
        if (typeof window.jQuery !== 'undefined' && window.jQuery !== $ && window.jQuery.fn.dataTable) {
            // DataTables registered on window.jQuery — copy it to Moodle's $.
            $.fn.dataTable         = window.jQuery.fn.dataTable;
            $.fn.DataTable         = window.jQuery.fn.DataTable;
            $.fn.dataTableSettings = window.jQuery.fn.dataTableSettings;
            $.fn.dataTableExt     = window.jQuery.fn.dataTableExt;
        }

        // If still not available, bail gracefully.
        if (!$.fn.dataTable) {
            return;
        }

        // Active filter token.
        var activeFilter = 'filterrow';

        // Custom search plugin: filter rows by their CSS class.
        $.fn.dataTable.ext.search.push(function(settings, _data, rowIndex) {
            if (settings.nTable.id !== tableId) {
                return true;
            }
            if (activeFilter === 'filterrow') {
                return true;
            }
            var tr = settings.aoData[rowIndex] && settings.aoData[rowIndex].nTr;
            if (!tr) {
                return true;
            }
            return tr.classList.contains(activeFilter);
        });

        // Initialise DataTables.
        var dt = $(tableEl).DataTable({
            // No ordering on recommandations and actions columns.
            columnDefs: [
                {orderable: false, targets: -1},
                {orderable: false, targets: -2}
            ],
            stripeClasses: ['dt-odd', 'dt-even'],
            order: [[0, 'asc']],
            pageLength: 25,
            lengthMenu: [10, 25, 50, 100],
            dom:
                '<"d-flex align-items-center justify-content-between mb-3"' +
                    '<"text-muted small"l>' +
                    '<"text-muted small"i>' +
                '>rt' +
                '<"d-flex align-items-center justify-content-center mt-3"p>',
            language: {
                lengthMenu:   lang.lengthMenu,
                info:         lang.info,
                infoEmpty:    lang.infoEmpty,
                infoFiltered: lang.infoFiltered,
                zeroRecords:  lang.zeroRecords,
                paginate: {
                    first:    lang.first,
                    last:     lang.last,
                    next:     lang.next,
                    previous: lang.previous,
                }
            },
            drawCallback: function() {
                var tbl = document.getElementById(tableId);
                if (tbl) {
                    tbl.querySelectorAll("tbody td").forEach(function(td) {
                        td.style.removeProperty("background-color");
                    });
                    tbl.querySelectorAll("tbody tr").forEach(function(tr) {
                        tr.style.removeProperty("background-color");
                        // Apply stripe colors directly via JS.
                        var bgColor = tr.classList.contains('dt-odd') ? '#f5f5f5' : '#ffffff';
                        tr.querySelectorAll('td').forEach(function(td) {
                            td.style.backgroundColor = bgColor;
                        });
                    });
                }
            },
            initComplete: function() {
                $(this.api().table().node())
                    .addClass('admintable generaltable browse_courses w-100');
            }
        });

        // Filter buttons.
        document.querySelectorAll('.coursemanager-filter-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                document.querySelectorAll('.coursemanager-filter-btn')
                    .forEach(function(b) { b.classList.remove('active'); });
                btn.classList.add('active');
                activeFilter = btn.dataset.filter || 'filterrow';
                dt.draw();
            });
        });

        // Text search (replaces search_courses.js).
        var searchInput = document.getElementById('coursemanager-search');
        if (searchInput) {
            searchInput.addEventListener('keyup', function() {
                dt.search(searchInput.value).draw();
            });
        }
    };

    return {
        /**
         * Entry point called by $PAGE->requires->js_call_amd().
         *
         * @param {string} tableId  HTML id of the table element to enhance.
         * @param {Object} lang     Localised strings passed from PHP.
         */
        init: function(tableId, lang) {
            // DataTables CSS (Bootstrap 5).
            var link  = document.createElement('link');
            link.rel  = 'stylesheet';
            link.href = 'https://cdnjs.cloudflare.com/ajax/libs/datatables.net-bs5/1.13.6/dataTables.bootstrap5.min.css';
            document.head.appendChild(link);

            // Load DataTables core with AMD hidden, then pass Moodle's $ to its factory.
            loadScriptNoAmd(
                'https://cdnjs.cloudflare.com/ajax/libs/datatables.net/1.13.6/jquery.dataTables.min.js',
                function() {
                    // While define is still hidden, call DataTables factory with Moodle's $.
                    // DataTables exports a factory function when no AMD/CommonJS is detected.
                    if (typeof window.jQuery === 'undefined') {
                        // DataTables fell back to factory mode — call it with our $.
                        // The factory is stored as the last script's return value isn't
                        // accessible directly, but DataTables attaches to whatever $ it finds.
                        // Force it by temporarily exposing our $ as window.jQuery.
                        window.jQuery = $;
                    }
                }
            ).then(function() {
                return loadScriptNoAmd(
                    'https://cdnjs.cloudflare.com/ajax/libs/datatables.net-bs5/1.13.6/dataTables.bootstrap5.min.js'
                );
            }).then(function() {
                initTable(tableId, lang);
            });
        }
    };
});